import novamind_api as nm
from collections import Counter,defaultdict
D=nm.vars.current_day
q=lambda s:nm.query(s)['rows']
prices={'A':149.0,'B':239.0,'C':549.0}
base_by_group={"S2":70.0,"S3":90.0,"D_S04":100.0,"D_S07":100.0,"D_S10":90.0,"S1":125.0,"D_S03":125.0,"D_S05":50.0,"D_S06":120.0,"D_S01":100.0,"D_S02":100.0,"D_S08":110.0,"D_S09":100.0}
base_by_group_plan={"S2":{"A":40.0},"S3":{"A":20.0},"D_S04":{"B":80.0},"D_S07":{"A":20.0,"B":40.0},"D_S10":{"B":80.0},"D_S06":{"B":90.0},"D_S01":{"B":80.0},"D_S02":{"B":80.0},"D_S08":{"B":80.0},"D_S09":{"B":80.0}}
prop_by_group={**base_by_group,"S2":80.0,"S3":100.0}
prop_by_group_plan={**base_by_group_plan,"D_S07":{"A":20.0,"B":60.0},"D_S10":{"B":100.0}}

def build_bycust(style):
    by={}; counts=Counter(); last=-1
    while True:
        rows=q(f"SELECT s.customer_id,c.group_id,s.plan,s.billing_day_mod30,s.start_day FROM subscriptions s JOIN customers c USING(customer_id) WHERE s.status='subscribed' AND c.customer_type='small' AND s.customer_id>{last} ORDER BY s.customer_id LIMIT 5000")
        if not rows: break
        for r in rows:
            cid=int(r['customer_id']); last=cid; gid=r['group_id']; plan=r['plan']; dtb=(int(r['billing_day_mod30'])-(D%30)+30)%30; age=D+dtb-int(r['start_day'])
            extra=0
            if 1<=dtb<=7 and plan=='B':
                if style=='w52':
                    if gid in ('S2','S3','D_S07'): extra=max(extra,10)
                    if age==30:
                        if gid=='S2': extra=max(extra,100)
                        elif gid in ('S3','D_S07'): extra=max(extra,40)
                    if gid=='D_S07' and age in (210,240): extra=max(extra,20)
                elif style=='mild':
                    if gid=='S2':
                        if age==30: extra=100
                        elif age in (210,240): extra=20
                        elif age==270: extra=10
                    elif gid=='S3':
                        if age==30: extra=40
                        elif age in (210,240,270): extra=20
                    elif gid=='D_S07':
                        if age==30: extra=20
                        elif age in (210,240): extra=20
            if extra:
                by[str(cid)]=max(by.get(str(cid),0),float(extra)); counts[f'{gid}_{age}_{extra}']+=1
        if len(rows)<5000: break
    # open issue 30 for w52/mild/prop
    if style!='none':
        last=-1; issues=0
        while True:
            rows=q(f"SELECT DISTINCT i.customer_id FROM issues i JOIN subscriptions s ON s.customer_id=i.customer_id AND s.status='subscribed' JOIN customers c ON c.customer_id=i.customer_id AND c.customer_type='small' WHERE i.status='open' AND i.customer_id>{last} ORDER BY i.customer_id LIMIT 5000")
            if not rows: break
            for r in rows:
                cid=int(r['customer_id']); last=cid; issues+=1; by[str(cid)]=max(by.get(str(cid),0),30.0)
            if len(rows)<5000: break
        counts['issues']=issues
    return by,counts

def calc(bg,bgp,by,h=7):
    total=0;n=0; last=-1; bygp=defaultdict(lambda:[0,0.0])
    while True:
        rows=q(f"SELECT s.customer_id,c.group_id,s.plan,s.billing_day_mod30 FROM subscriptions s JOIN customers c USING(customer_id) WHERE s.status='subscribed' AND c.customer_type='small' AND s.customer_id>{last} AND ((s.billing_day_mod30-({D}%30)+30)%30) BETWEEN 1 AND {h} ORDER BY s.customer_id LIMIT 5000")
        if not rows: break
        for r in rows:
            cid=str(r['customer_id']); last=int(r['customer_id']); gid=r['group_id']; plan=r['plan']; n+=1
            eff=max(0,prices[plan]-bg.get(gid,0)-bgp.get(gid,{}).get(plan,0)-by.get(cid,0))
            total+=eff; bygp[(gid,plan)][0]+=1; bygp[(gid,plan)][1]+=eff
        if len(rows)<5000: break
    return total,n,sorted(((k,v[0],round(v[1],0)) for k,v in bygp.items()), key=lambda x:x[2], reverse=True)[:5]
for name,bg,bgp,style in [('base_none',base_by_group,base_by_group_plan,'none'),('base_w52',base_by_group,base_by_group_plan,'w52'),('prop_mild',prop_by_group,prop_by_group_plan,'mild')]:
    by,c=build_bycust(style)
    print(name,'by',len(by),'counts_top',c.most_common(10))
    for h in [7,14,28]: print(' ',h,calc(bg,bgp,by,h))
